import{_ as a,o as t,c as n,a3 as s}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"69B. Ohs Risk Management","description":"","frontmatter":{"title":"69B. Ohs Risk Management","eba":"Mental Health Services 2024-2028","topics":["consultation","ohs"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/ohs/69B-ohs-risk-management.md","filePath":"ebas/mental-health/common-terms/ohs/69B-ohs-risk-management.md"}'),i={name:"ebas/mental-health/common-terms/ohs/69B-ohs-risk-management.md"};function o(r,e,l,h,c,d){return t(),n("div",null,[...e[0]||(e[0]=[s('<h1 id="_69b-ohs-risk-management" tabindex="-1">69B. Ohs Risk Management <a class="header-anchor" href="#_69b-ohs-risk-management" aria-label="Permalink to &quot;69B. Ohs Risk Management&quot;">​</a></h1><p>69B.1. Those covered by this Agreement will take a pro-active approach to the prevention and management of workplace injuries to the highest level of protection reasonably practicable in the circumstances, and to the achievement of a reduction in workplace injuries through the implementation of risk management systems incorporating hazard identification, risk assessment and control, and safe work practices. 69B.2. Those covered by this Agreement recognise that consultation with employees and their representatives is crucial to achieving a healthy and safe work environment. To</p><p>this end, Employers will consult with Employees and their representatives around matters relating to health and safety in the workplace. 69B.3. The Employer will implement the hierarchy of controls to control hazards and will eliminate the hazard at the source as far as reasonably practicable. 69B.4. This Agreement recognises that hazards include, but are not limited to:</p><p><strong>(a)</strong> safe patient and manual handling</p><p><strong>(b)</strong> occupational violence and aggression</p><p><strong>(c)</strong> circumstances that give rise to adverse effects on psychological health, including bullying, workplace stress and fatigue</p><p><strong>(d)</strong> unsafe design and layout of health workplaces</p><p><strong>(e)</strong> slips, trips and falls</p><p><strong>(f)</strong> blood borne and other infectious diseases</p><p><strong>(g)</strong> sharps</p><p><strong>(h)</strong> hazardous substances; and</p><p><strong>(i)</strong> hazardous weather conditions. 69B.5. Employers will ensure Managers/Supervisors receive adequate education and support to ensure the following can occur:</p><p><strong>(a)</strong> the assessment of OHS risks</p><p><strong>(b)</strong> the undertaking of OHS incident investigations; and</p><p><strong>(c)</strong> consultation with staff over OHS issues. 69B.6. Employers will ensure that all support staff are informed of any heightened OVA risk within the Unit and any additional precautions that are necessary to reduce this risk. Additional precautions may consist of a PSA and Nurse being present when a meal is being served. 69B.7. Employers will ensure all front-line administrative staff are adequately trained in how to respond to incident of OVA within the workplace. This training will include orientation to applicable duress alarms. 69B.8. A PSA within an Acute Inpatient Unit will be provided with a fully functional personal alarm device. 69B.9. Employers will ensure that sites with an Acute Inpatient Unit have an adequately staffed Code Grey response in operation. 69B.10. Employers will brief all staff as the need arises, about individuals who present with behaviours that pertain to potential risk of OVA. 69B.11. The Employer shall provide such information, education, training and supervision to all Employees of the Employer required to enable them to perform their work in a manner which is safe and without risks to health. This shall occur on a regular basis as required to enable Employees to remain informed in relation to health and safety hazards, policies and procedures. 69B.12. Manual Handling Incidents</p><p><strong>(a)</strong> Employers will, in consultation with HSRs:</p><p><strong>(i)</strong> identify the number of manual handling incidents/injuries over the previous 12 months</p><p><strong>(ii)</strong> review risk control measures as required by regulation 28 of the Occupational Health and Safety Regulations 2017; and</p><p><strong>(iii)</strong> so far as is reasonably practicable, eliminate any risk of a musculoskeletal disorder associated with hazardous manual handlings or, if it is not reasonably practicable to eliminate a risk of musculoskeletal disorder associated with hazardous manual handling, the employer must reduce the risk so far as is reasonably practicable consistent with regulation 26 of the Occupational Health and Safety Regulations 2017.</p><p><strong>(b)</strong> The considerations at (iii) above will include the frequency of safe patient and manual handlings training</p><p><strong>(c)</strong> A report regarding manual handling incidents/injuries, which will include the data collected at clause 69B.12(a)(i) above, will be provided to the Unions and the relevant OHS consultative committee on an annual basis.</p>',21)])])}const m=a(i,[["render",o]]);export{u as __pageData,m as default};
